#include <stdio.h>
#include <math.h>
#include <stdlib.h>

static void conv(const double *a, const double *b, double *c, int N) {
    for (int i = 0; i <= N; ++i) c[i] = 0.0;
    for (int i = 0; i <= N; ++i) {
        if (a[i]==0.0) continue;
        for (int j = 0; j <= N - i; ++j) {
            c[i + j] += a[i] * b[j];
        }
    }
}

int main(){
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        long long M; int N; double X;
        scanf("%lld %d %lf", &M, &N, &X);
        double base[31];
        for (int k = 0; k <= N; ++k) base[k] = cos(k * X / N);
        double res[31] = {0}; res[0] = 1.0;
        double tmp[31];
        while (M > 0) {
            if (M & 1LL) {
                conv(res, base, tmp, N);
                for (int i = 0; i <= N; ++i) res[i] = tmp[i];
            }
            conv(base, base, tmp, N);
            for (int i = 0; i <= N; ++i) base[i] = tmp[i];
            M >>= 1LL;
        }
        printf("%.10f\n", res[N]);
    }
    return 0;
}

