import java.io.*;
import java.util.*;

public class Main {
    private static double[] conv(double[] a, double[] b, int N) {
        double[] c = new double[N+1];
        for (int i = 0; i <= N; i++) {
            if (a[i] == 0.0) continue;
            for (int j = 0; j <= N - i; j++) {
                c[i + j] += a[i] * b[j];
            }
        }
        return c;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            st = new StringTokenizer(br.readLine());
            long M = Long.parseLong(st.nextToken());
            int N = Integer.parseInt(st.nextToken());
            double X = Double.parseDouble(st.nextToken());
            double[] base = new double[N+1];
            for (int k = 0; k <= N; k++) base[k] = Math.cos(k * X / N);
            double[] res = new double[N+1];
            res[0] = 1.0;
            while (M > 0) {
                if ((M & 1L) == 1L) res = conv(res, base, N);
                base = conv(base, base, N);
                M >>= 1;
            }
            sb.append(String.format(java.util.Locale.US, "%.10f", res[N])).append('\n');
        }
        System.out.print(sb.toString());
    }
}

