import sys, math

def conv(a, b, N):
    c = [0.0] * (N + 1)
    for i in range(N + 1):
        ai = a[i]
        if ai == 0.0:
            continue
        for j in range(N - i + 1):
            c[i + j] += ai * b[j]
    return c

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        M = int(next(it))
        N = int(next(it))
        X = float(next(it))
        base = [math.cos(k * X / N) for k in range(N + 1)]
        res = [0.0] * (N + 1)
        res[0] = 1.0
        while M > 0:
            if M & 1:
                res = conv(res, base, N)
            base = conv(base, base, N)
            M >>= 1
        out_lines.append(f"{res[N]:.10f}")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

